class Solution {
public:
    vector<int> solve(vector<int>& times) {
        vector<int> result;
        int i = 0;
        while (i < times.size()) {
            int j = i;
            while (j < times.size() && times[j] <= times[i] + 1) {
                result.push_back(j);
                j++;
            }
            i = j;
        }
        return result;
    }
};

