class Solution:
    def solve(self, times: list[int]) -> list[int]:
        result = []
        i = 0
        while i < len(times):
            j = i
            while j < len(times) and times[j] <= times[i] + 1:
                result.append(j)
                j += 1
            i = j
        return result

